var UserConnection = Get<UserConnection>("UserConnection");
string stringParam = Get<string>("StringParam");
Guid lineDetailId = Get<Guid>("LineDetailId");

try {
    var validCorpPortIn = new ValidateCorporatePortInService(UserConnection);
    if(string.IsNullOrEmpty(stringParam) && lineDetailId == Guid.Empty) {
        throw new Exception("String Param / Line Detail must be filled in one of them");
    }

    if(!string.IsNullOrEmpty(stringParam) && lineDetailId == Guid.Empty) {
        validCorpPortIn.SetParam(stringParam)
            .Request().GetAwaiter().GetResult();
    }

    if(string.IsNullOrEmpty(stringParam) && lineDetailId != Guid.Empty) {
        validCorpPortIn.SetParam(lineDetailId)
            .Request().GetAwaiter().GetResult();
    }

    Set("Request", validCorpPortIn.GetStringRequest());
    Set("Response", validCorpPortIn.GetStringResponse());
	if(!validCorpPortIn.IsSuccessResponse()) {
        throw new Exception(validCorpPortIn.GetErrorResponse());
    }
} catch (Exception e) {
    Set("Message", e.Message);
}

return true;
